// AUTO-GENERATED by @aquila/stories compiler. Do not edit by hand.

import type { DialogueEntry } from '../../../types';
import { CharacterId } from '../characters';
import { Portrait } from '../portraits';
import { Background } from '../backgrounds';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "07:25。", background: Background.Chapter_6_Ch6_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校史館側廊。", background: Background.Chapter_6_Ch6_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言靠在側廊轉角的柱子後面。這條廊連接主樓一樓和校史館側門，全長不到三十步。一邊是貼著舊照片的磨砂玻璃展櫃，一邊是靠牆的常綠盆栽。地上的積水還沒有被踩過，灰色的天光從廊頂的透明浪板漏下來，把整條走廊染成一種均勻的、冷的灰。", background: Background.Chapter_6_Ch6_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她會來。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）前五輪，她早上都走這條廊。七點二十到七點半之間。從主樓方向過來，去校史館側門檢查攝影器材。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）每一次。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）等。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "雨聲從廊頂的浪板上下來，像一層不停被拉扯的白噪音。遠處操場方向偶爾傳來搬桌子的聲響——校慶佈置組已經開始幹活了。但這條廊上沒有人。", background: Background.Chapter_6_Ch6_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）上一輪我花了一整天找不死的方法。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這一輪我只做一件事。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）找到她。在她走進校史館之前。在她拍基座底板之前。在她把相機包帶進後台之前。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）在 23:00 之前。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "腳步聲從主樓方向過來。", background: Background.Chapter_6_Ch6_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不急。但很穩。膠底鞋踩過積水的節奏太均勻了——和校慶裡其他人不一樣。其他人走路是隨意的，會停、會看手機、會繞水坑。這個腳步聲不繞。每一步的落點都像被量過。", background: Background.Chapter_6_Ch6_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）是她。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠從轉角出現。", background: Background.Chapter_6_Ch6_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "攝影背心，藍色工作證，相機包斜挎在身側，帶子勒進深灰色背心的肩線裡。她低著頭看手機，螢幕的白光照在她下半張臉上。碎髮被濕氣黏在耳側。她走得快，但上半身幾乎不晃——像有人在她頭頂放了一碗水，叫她不能灑。", background: Background.Chapter_6_Ch6_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）就是現在。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他從柱子後面走出來。擋在廊中間。", background: Background.Chapter_6_Ch6_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "許星棠。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她停下來。抬起頭。", background: Background.Chapter_6_Ch6_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的眼睛對上他的那一秒，顧言看見的不是驚訝。是一種很安靜的、像在調焦距一樣的凝視。瞳仁很亮。但那種亮不是熱的——是深水面的反光。看得到表面，猜不到深度。", background: Background.Chapter_6_Ch6_Act1_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "⋯⋯", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她認出我了。前幾輪她見過我。在雨棚。在走廊。在操場邊。她知道我是誰。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）說。現在就說。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "今晚——", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "23:00。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "妳會死。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "廊裡的雨聲沒有變。常綠盆栽的葉子上積水往下滴。什麼都沒有變。", background: Background.Chapter_6_Ch6_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但許星棠的表情變了。", background: Background.Chapter_6_Ch6_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是恐懼。不是困惑。不是那種「這個人在說什麼」的空白。", background: Background.Chapter_6_Ch6_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她退了半步。", background: Background.Chapter_6_Ch6_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "右手落在相機包的帶子上，指節收攏。動作很小，快得像反射——像練習過很多次——聽到某些詞，就該怎麼動。", background: Background.Chapter_6_Ch6_Act1_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "誰讓你來的。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是問句。是質問。聲音平得像剛刷過漆的牆。", background: Background.Chapter_6_Ch6_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不對。她的反應不對。她沒有驚訝。沒有問我為什麼、怎麼知道。她在——定位。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她在判斷我是誰的人。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "沒有人——", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "聽我說。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "後台。今晚閉幕直播。23:00 切換。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "有人會阻止妳。穿黑雨衣的。他知道妳母親。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他說得太快了。每一個詞都像在搶時間——後台、黑雨衣、23:00、她母親。他知道自己在說什麼，但這些詞從嘴裡出來的順序是亂的。像把一整盒拼圖往桌上倒，指望對方自己能拼出來。", background: Background.Chapter_6_Ch6_Act1_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你說了很多東西。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "後台。黑雨衣。23:00。我母親。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你從哪裡知道這些的。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她在收集。不是在害怕。她在把我說的每一個詞收進去，像拍照一樣存檔。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我越說，她越冷。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "我看過。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "上一輪——", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不行。不能說循環。她不會信。她只會覺得我瘋了，或者覺得這是更精心設計的謊話。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "我在後台門外。看見妳在備份線旁邊。有人被攔住了。林主任在側台。黑雨衣從通道出來。23:00——妳倒下了。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他一口氣說完。聲音壓得很低，但每一個字都很清楚。廊裡只有他和她。雨聲蓋住了一切，但也像把這段話封進了一個只有兩個人的容器裡。", background: Background.Chapter_6_Ch6_Act1_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "⋯⋯", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沉默了大概三秒。", background: Background.Chapter_6_Ch6_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "三秒。在雨聲裡很長。", background: Background.Chapter_6_Ch6_Act1_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你知道我母親。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你父親的事全校都知道。但你知道我母親——知道她跟校史館、跟後台的關係——", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "這不正常。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她在篩。我說的每句話她都在篩——哪些是公開資訊，哪些不是。「縱火犯之子」是公開的。但她母親和校史館的關係不是。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）在她眼裡，我不像一個好心的同學。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我像一個做過功課的人。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你到底是想幫我，還是想找出相機在哪。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯相機。她直接說了相機。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她的假設是——我是來找相機的。不是來救她的。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "我不要相機。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "我沒提相機。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "空氣停了一下。", background: Background.Chapter_6_Ch6_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯她對。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她沒有提相機。是我提的。我自己說出來的。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她想看我的反應。她丟出一個陷阱詞，我自己踩進去了。她想確認我來之前就知道她身上有相機——知道相機是核心。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）而我證實了。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠的目光沒有離開他的臉。那雙深水的眼睛不動，但底下有什麼在動——不是憤怒。是一種很冷的、在計算風險的東西。", background: Background.Chapter_6_Ch6_Act1_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "顧言。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你知道的太多。說得太急。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "不管你是誰叫來的——", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "先證明你不是來找相機的。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有等他回答。她轉身，相機包的帶子在她肩上繃了一下。腳步聲重新開始——和來時一樣均勻、一樣穩。", background: Background.Chapter_6_Ch6_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她走進雨裡。低馬尾的末端被風掀了一下。她沒有回頭。", background: Background.Chapter_6_Ch6_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "廊裡又只剩他一個人。雨聲。浪板。積水。盆栽葉子上的水滴。", background: Background.Chapter_6_Ch6_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯失敗了。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我以為知道她會死就夠了。以為把真相擺在她面前，她就會信。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但對她來說，知道太多的人不是救星。是威脅。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她沒有錯。她手上有真正的東西——相機、證據、她母親留下來的線索。任何靠近她的人都有可能是來拿走那些東西的。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）包括我。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我不能靠嘴說服她。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我得讓她親眼看見。", background: Background.Chapter_6_Ch6_Act1_S0, portrait: Portrait.GuYan_Determined },
];
